		-- {1211, 1212, 1213}
		introduction = '尼多力诺，毒针宝可梦。是尼多朗的进化形。额头上的独角的威力变得更加强大。',
		introduction_tw = '尼多力諾，毒針寶可夢。是尼多朗的進化形。額頭上的獨角的威力變得更加強大。',
