		-- {13511, 13512, 13513}
		introduction = '夜行性，太阳下山后就会开始活动。如果看到垂钓者，就会从水中扯线捣乱并引以为乐。',
		introduction_tw = '夜行性，太陽下山後就會開始活動。如果看到垂釣者，就會從水中扯線搗亂並引以為樂。',
		introduction_en = 'Nocturnal - it will get active after dusk. It is also a mischief-maker. When this Pokémon spots anglers, it tugs on their fishing lines from beneath the surface and enjoys their consternation.',
		introduction_vn = 'Nocturnal - it will get active after dusk. It is also a mischief-maker. When this Pokémon spots anglers, it tugs on their fishing lines from beneath the surface and enjoys their consternation.',
		introduction_kr = '야행성으로, 해 질 무렵이 되면 활동을 시작한다. 낚시꾼을 발견하면 물속에서 줄을 당겨 방해하고는 기뻐한다.',
		introduction_pt = 'Noturno - ele fica ativo após o anoitecer. Ele também é um criador de travessuras. Quando este Pokémon avista pescadores, ele puxa suas linhas de pesca de baixo da superfície e se diverte com a consternação deles.',
		introduction_th = 'ออกหากินเวลากลางคืน - มันจะตื่นตัวหลังจากพลบค่ำ นอกจากนี้ยังเป็นตัวก่อกวนอีกด้วย เมื่อโปเกมอนตัวนี้พบเห็นนักตกปลา มันจะดึงสายเบ็ดจากใต้ผิวน้ำและเพลิดเพลินไปกับความตื่นตระหนกของนักตกปลา',
