		starEffectIndex = 4,
		effortSeqID = 4,
		gemPosSeqID = 4,
		gemQualitySeqID = 4,
		fetterList = __data_t__fetterList[3632],
		-- {36311, 36312, 36313, 36314}
		introduction = '当体表的杂质剥落，超级蒂安希沐浴在光芒中，耀眼得无法直视，头部的钻石超过2000克拉。那副高贵美丽的模样被称作“皇家粉色公主”。它能将空气中的碳元素压缩在两手之间，一瞬间制造出许多的钻石。',
		introduction_tw = '當體表的雜質剝落，超級蒂安希沐浴在光芒中，耀眼得無法直視，頭部的鑽石超過2000克拉。那副高貴美麗的模樣被稱為「皇家粉紅色公主」。它能將空氣中的碳元素壓縮在兩手之間，一瞬間製造出許多的鑽石。',
		introduction_en = 'When the impurities on its body peel off, Mega Diancie bathes in a brilliant light so dazzling that it is impossible to look directly at it, with a diamond on its head exceeding 2000 carats. This noble and beautiful appearance is referred to as the "Royal Pink Princess." It can compress carbon elements in the air between its hands and instantly create numerous diamonds.',
		introduction_vn = 'When the impurities on its body peel off, Mega Diancie bathes in a brilliant light so dazzling that it is impossible to look directly at it, with a diamond on its head exceeding 2000 carats. This noble and beautiful appearance is referred to as the "Royal Pink Princess." It can compress carbon elements in the air between its hands and instantly create numerous diamonds.',
		introduction_kr = '체표의 불순물이 벗겨지면, 슈퍼 디안시는 눈부신 빛 속에서 목욕을 하며, 그 빛은 직접 볼 수 없을 정도로 눈부시고, 머리 위의 다이아몬드는 2000캐럿을 초과한다. 그 고귀하고 아름다운 모습은 \'로얄 핑크 프린세스\'라고 불린다. 그것은 공기 중의 탄소 원소를 양손 사이에 압축하여 순간적으로 많은 다이아몬드를 만든다.',
		introduction_pt = 'Quando as impurezas em seu corpo se soltam, Mega Diancie se banha em uma luz brilhante tão ofuscante que é impossível olhar diretamente para ela, com um diamante em sua cabeça que ultrapassa 2000 quilates. Essa aparência nobre e bela é chamada de "Princesa Rosa Real". Ela pode comprimir os elementos de carbono no ar entre suas mãos e criar instantaneamente numerosos diamantes.',
		introduction_th = 'เมื่อสิ่งสกปรกบนร่างกายหลุดออกไป, เมกะเดียนซี่จะอาบแสงสว่างที่จ้าเกินกว่าจะมองตรงๆ ได้ โดยมีเพชรบนหัวที่มีขนาดมากกว่า 2000 กะรัต รูปลักษณ์ที่สูงส่งและสวยงามนี้ถูกเรียกว่า "เจ้าหญิงสีชมพูราชวงศ์" มันสามารถบีบอัดธาตุคาร์บอนในอากาศระหว่างมือของมันและสร้างเพชรจำนวนมากในทันที',
		location = '星墙守护&钻石反射',
