		fetterList = __data_t__fetterList[3843],
		-- {38411, 38412, 38413, 38414}
		introduction = '甜冷美后，水果宝可梦，草属性。擅长使用脚踢招式，会踩着落败的对手夸耀胜利。据说甜冷美后头顶像王冠一样的部位一旦被触碰，力量便会消失。',
		introduction_tw = '甜冷美後，水果寶可夢，草屬性。擅長使用腳踢招式，會踩著落敗的對手誇耀勝利。據說甜冷美後頭頂像王冠一樣的部位一旦被觸碰，力量便會消失。',
		introduction_en = 'Tsareena, Fruit Pokémon, Grass type. Tsareena has very strong legs, making its kicking attacks very powerful. It steps on defeated opponents to signalize its victories. It\'s said that when one touches the crown-like part of Tsareena\'s head, its power will perish.',
		introduction_vn = 'Tsareena, Fruit Pokémon, Grass type. Tsareena has very strong legs, making its kicking attacks very powerful. It steps on defeated opponents to signalize its victories. It\'s said that when one touches the crown-like part of Tsareena\'s head, its power will perish.',
		introduction_kr = '달코퀸,과일 포켓몬,풀의 타입.발차기를 잘하면 지는 상대를 밟아 승리를 자랑한다.달코퀸 왕관 같은 부위가 닿으면 힘이 사라진다고 한다.',
		introduction_pt = 'Tsareena, Pokémon Fruta, tipo Grama. Tsareena tem pernas muito fortes, o que torna seus ataques de chute muito poderosos. Ela pisa em oponentes derrotados para sinalizar suas vitórias. Dizem que quando alguém toca a parte em forma de coroa da cabeça de Tsareena, seu poder perecerá.',
		introduction_th = 'ซารีน่า โปเกม่อนผลไม้ ประเภทหญ้า ซารีน่ามีขาที่แข็งแรงมาก ทำให้การเตะของมันมีพลังมาก มันเหยียบศัตรูที่พ่ายแพ้เพื่อเป็นสัญญาณแห่งชัยชนะ ว่ากันว่าเมื่อสัมผัสส่วนที่เหมือนมงกุฎบนศีรษะของซารีน่า พลังของมันจะสูญสลายไป',
		location = '暴力输出：热带连击',
