		unitID = 4024,
		skinSkillMap = {[129] = {40271, 40272, 40273, 40276, 60000001, 60000002}, __size = 1},
		innateSkillID = 40243,
		skillList = {40241, 40242, 40243, 40246, 60000001, 60000002},
