		-- {['drawcard'] = 'huang_effect_loop', __size = 1}
		starEffectIndex = 4,
		effortSeqID = 4,
		gemPosSeqID = 4,
		gemQualitySeqID = 4,
		fetterList = {40241, 40242, 40243, 40244},
		introduction = '露奈雅拉是阿罗拉地区的传说的宝可梦。自远古时代起，它就作为月亮之使者备受尊崇，古人以敬畏的心称之为“邀引月亮之兽”。据说它是栖息在其他世界的，当第三只眼浮现时就会飞去其他世界，有时候会从通往异世界的洞穴里把未知的力量和生命召唤到这个世界来',
		introduction_tw = '露奈雅拉是阿羅拉地區的傳說的寶可夢。自遠古時代起，它就作為月亮之使者備受尊崇，古人以敬畏的心稱之為「邀引月亮之獸」。據說它是棲息在其他世界的，當第三隻眼浮現時就會飛去其他世界，有時會從通往異世界的洞穴裡把未知的力量和生命召喚到這個世界來',
		introduction_en = 'Lunala is a legendary Pokémon from the Alola region. Since ancient times, it has been revered as the messenger of the moon, and the ancients called it "the beast that invites the moon" with awe. It is said that it lives in other worlds, and when its third eye emerges, it will fly to other worlds. Sometimes it will summon unknown powers and lives to this world from the cave leading to the other world.',
		introduction_vn = 'Lunala is a legendary Pokémon from the Alola region. Since ancient times, it has been revered as the messenger of the moon, and the ancients called it "the beast that invites the moon" with awe. It is said that it lives in other worlds, and when its third eye emerges, it will fly to other worlds. Sometimes it will summon unknown powers and lives to this world from the cave leading to the other world.',
		introduction_kr = '루나라는 알로라 지방의 전설의 포켓몬입니다. 고대부터 달의 사자로 존경을 받아왔고, 고대인들은 "달을 초대하는 짐승"이라고 경외감을 가지고 불렀습니다. 다른 세계에 살고 있다고 하며, 제3의 눈이 나타나면 다른 세계로 날아간다고 합니다. 때로는 다른 세계로 통하는 동굴에서 알려지지 않은 힘과 생명을 이 세계로 불러들이기도 합니다.',
		introduction_pt = 'Lunala é um Pokémon lendário da região de Alola. Desde os tempos antigos, ele é reverenciado como o mensageiro da lua, e os antigos o chamavam de "a besta que convida a lua" com admiração. Dizem que ele vive em outros mundos e, quando seu terceiro olho emerge, ele voa para outros mundos. Às vezes, ele invoca poderes desconhecidos e vive para este mundo da caverna que leva ao outro mundo.',
		introduction_th = 'ลูนาล่าเป็นโปเกมอนในตำนานจากภูมิภาคอโลล่า ตั้งแต่สมัยโบราณ ลูนาล่าได้รับการยกย่องว่าเป็นทูตของดวงจันทร์ และคนโบราณเรียกมันว่า "สัตว์ร้ายที่เชื้อเชิญดวงจันทร์" ด้วยความเกรงขาม ลูนาล่ากล่าวกันว่าอาศัยอยู่ในโลกอื่น และเมื่อดวงตาที่สามของมันปรากฏขึ้น มันจะบินไปยังโลกอื่น บางครั้งมันจะเรียกพลังและสิ่งมีชีวิตที่ไม่รู้จักมายังโลกนี้จากถ้ำที่นำไปสู่อีกโลกหนึ่ง',
		location = '潜灵奇袭&月相掌控',
		location_tw = '潛靈奇襲&月相掌控',
		location_en = 'Phantom Force&Moonraze Maelstrom',
		location_vn = 'Phantom Force&Moonraze Maelstrom',
		location_kr = '달 충돌과 달의 위상',
		location_pt = 'Ataques lunares e fases da lua',
		location_th = 'ดวงจันทร์และเฟสของดวงจันทร์'
	},
