		-- {['drawcard'] = 'huang_effect_loop', __size = 1}
		starEffectIndex = 4,
		effortSeqID = 4,
		gemPosSeqID = 4,
		gemQualitySeqID = 4,
		fetterList = {41011, 41012, 41013, 41014},
		introduction = '夺取光的传说宝可梦，似乎一直都沉睡在地下，传闻是太古时代从其他世界来到此地的类似究极异兽的生物。如果不吃光的话，杂质会慢慢积聚进而发黑不能动弹，因此会为了寻求光而暴走，从对手身上吸取光能，双手的棱镜可发射出强力的贯穿任何事物的镭射光线',
		introduction_tw = '奪取光的傳說寶可夢，似乎一直都沉睡在地下，傳聞是太古時代從其他世界來到此地的類似究極異獸的生物。如果不吃光的話，雜質會慢慢積聚進而發黑不能動彈，因此會為了尋求光而暴走，從對手身上吸取光能，雙手的棱鏡可發射出強力的貫穿任何事物的鐳射光線',
		introduction_en = 'A legendary Pokémon that steals light, it seems to have been asleep underground for eons. Rumors say it came from another world in ancient times, resembling an ultimate beast. If it doesn\'t consume light, impurities will slowly accumulate, causing it to turn black and unable to move. As a result, it goes on a rampage seeking light, absorbing energy from its opponents. The prisms on its hands can emit powerful laser beams that pierce through anything.',
		introduction_vn = 'A legendary Pokémon that steals light, it seems to have been asleep underground for eons. Rumors say it came from another world in ancient times, resembling an ultimate beast. If it doesn\'t consume light, impurities will slowly accumulate, causing it to turn black and unable to move. As a result, it goes on a rampage seeking light, absorbing energy from its opponents. The prisms on its hands can emit powerful laser beams that pierce through anything.',
		introduction_kr = '빛을 빼앗는 전설의 포켓몬으로, 오랫동안 지하에서 잠들어 있었던 것으로 보입니다. 고대 시대에 다른 세계에서 온 것으로 전해지며, 궁극적인 괴물과 비슷한 존재로 알려져 있습니다. 빛을 섭취하지 않으면 불순물이 서서히 쌓여 검게 변하고 움직일 수 없게 되기 때문에, 빛을 찾기 위해 광폭화하고 상대에서 빛 에너지를 흡수합니다. 손에 있는 프리즘은 모든 것을 관통하는 강력한 레이저 광선을 발사할 수 있습니다.',
		introduction_pt = 'Um Pokémon lendário que rouba a luz, parece estar adormecido sob a terra há milênios. Diz-se que veio de outro mundo nos tempos antigos, assemelhando-se a uma besta suprema. Se não consumir luz, impurezas se acumulam lentamente, fazendo com que fique preto e incapaz de se mover. Por isso, entra em um frenesi em busca de luz, absorvendo energia de seus oponentes. Os prismas em suas mãos podem emitir feixes poderosos de laser que atravessam qualquer coisa.',
		introduction_th = 'โปเกม่อนตำนานที่ขโมยแสง มันดูเหมือนจะหลับไหลอยู่ใต้ดินมานานแสนนาน มีข่าวลือว่ามันมาจากโลกอื่นในยุคโบราณ คล้ายกับสัตว์อสูรสุดยอด หากมันไม่ได้กินแสง สิ่งสกปรกจะสะสมจนกลายเป็นสีดำและไม่สามารถขยับได้ ดังนั้นมันจึงบ้าคลั่งเพื่อหแสง โดยดูดพลังจากคู่ต่อสู้ รอยตัดที่มือสามารถยิงลำแสงเลเซอร์ที่ทรงพลังทะลุผ่านสิ่งใดก็ได้',
		location = '群体控制',
		location_tw = '群體控制',
		location_en = 'Predator of Light',
		location_vn = 'Predator of Light',
		location_kr = '군중 통제',
		location_pt = 'Controle de multidão',
		location_th = 'การควบคุมฝูงชน'
	},
